--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `products` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(180) NOT NULL,
  `price` decimal(10,2) NOT NULL DEFAULT 0.00,
  `category` varchar(120) NOT NULL,
  `category_id` int(11) DEFAULT NULL,
  `subcategory_id` int(11) DEFAULT NULL,
  `image` varchar(255) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `slug` varchar(160) DEFAULT NULL,
  `brand` varchar(120) DEFAULT NULL,
  `sku` varchar(80) DEFAULT NULL,
  `original_price` decimal(10,2) DEFAULT 0.00,
  `discount_price` decimal(10,2) DEFAULT 0.00,
  `stock_quantity` int(11) DEFAULT 0,
  `short_description` text DEFAULT NULL,
  `full_description` text DEFAULT NULL,
  `specifications` text DEFAULT NULL,
  `material` varchar(120) DEFAULT NULL,
  `color` varchar(80) DEFAULT NULL,
  `dimensions` varchar(120) DEFAULT NULL,
  `weight` varchar(80) DEFAULT NULL,
  `seating_capacity` varchar(80) DEFAULT NULL,
  `room_type` varchar(120) DEFAULT NULL,
  `assembly_required` varchar(20) DEFAULT 'No',
  `featured` tinyint(1) DEFAULT 0,
  `trending` tinyint(1) DEFAULT 0,
  `in_stock` tinyint(1) DEFAULT 1,
  `status` varchar(20) DEFAULT 'active',
  `gallery_images` text DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `image_1` varchar(255) DEFAULT NULL,
  `image_2` varchar(255) DEFAULT NULL,
  `image_3` varchar(255) DEFAULT NULL,
  `image_4` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_products_category` (`category`),
  KEY `idx_products_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=1314 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

